INSERT INTO public.recipe_ingredients (recipe_id, ingredient_id, quantity, unit, notes, position) VALUES ('9f7eaf07-478c-4987-a263-2d0adc490fda', '343a578d-6035-49a1-9a65-ee5cbbfd31da', 1.000, 'unite', 'miso (miso blanc. il existe plusieurs types de miso, allant du blanc au rouge, en passant par un mélange des deux. Plus un miso est foncé plus il est salé. Le miso rouge ou ''akamiso'' convient pour les', 1) ON CONFLICT (recipe_id, ingredient_id) DO NOTHING;
