INSERT INTO public.recipe_ingredients (recipe_id, ingredient_id, quantity, unit, notes, position) VALUES ('9f7eaf07-478c-4987-a263-2d0adc490fda', 'c5f7263e-2fb6-44e1-8b72-45051b3bf7a0', 1.000, 'unite', 'shichimi togarashi (melange d''épices japonais, sesame noir et blanc, piment, écorce d''orange)', 3) ON CONFLICT (recipe_id, ingredient_id) DO NOTHING;
INSERT INTO public.recipe_ingredients (recipe_id, ingredient_id, quantity, unit, notes, position) VALUES ('9f7eaf07-478c-4987-a263-2d0adc490fda', '12aec57a-0135-424d-be22-d3969896d21c', 1.000, 'unite', 'tofu ferme (le tofu exite sous deux forme, le ferme et le souple, le souple ressemble à une crème, il ne se tient pas et ne convient donc pas ici) A noter que le tofu japonais a un gout spécifique plu', 4) ON CONFLICT (recipe_id, ingredient_id) DO NOTHING;
INSERT INTO public.recipe_ingredients (recipe_id, ingredient_id, quantity, unit, notes, position) VALUES ('9f7eaf07-478c-4987-a263-2d0adc490fda', '983fcb88-972a-4a99-a865-b39a2b83bf97', 1.000, 'unite', 'pois mange-tout', 5) ON CONFLICT (recipe_id, ingredient_id) DO NOTHING;
